from collections import deque

def topological_sort(graph):
    # Step 1: Find all nodes with no incoming edges (in-degrees of 0) and add them to the queue (initially, these have no dependencies)
    zero_in_degree = deque([node for node, edges in graph.items() if not edges] + [edge for edges in graph.values() if not edges])

    # Step 2: While there are nodes to process in the queue
    while zero_in_degree:
        # Get a node from the queue and add it to topological order
        current_node = zero_in_degree.popleft()
        top_order.append(current_node)

        # Reduce the in-degrees of its neighbors due to this move, if any are now 0, they will be added to the queue as well
        for neighbor in graph.get(current_node, []):
            incoming_edges = adjacency_list[neighbor] - {current_node}
            if not incoming_edges:
                zero_in_degree.append(neighbor)

        # Remove processed nodes from the graph temporarily to avoid cycles and redundant checks
        adjacency_list = {node: set(edges) for node, edges in graph.items() if node not in top_order}

    # Check for cycles or unreachable components (which would make a valid topological ordering impossible)
    if len(top_order) == len(graph):
        return top_order
    else:
        raise Exception("Graph has a cycle, no topological sorting possible")

# Example usage:
if __name__ == "__main__nocycle":
    graph = {
        'A': set(),
        'B': {'A'},
        'C': {'A', 'D'},
        'D': set(),
        'E': {'F', 'G'},
        'F': {'E'},
        'G': set()
    }

    top_order = topological_sort(graph)
    print("Topological order:", top_order)
